boolean isValidParenthesesString(String s, String locked) {
    int balance = 0;
    for (int i = 0; i < s.length(); i++) {
        if (locked.charAt(i) == '0') {
            balance += s.charAt(i) == '(' ? 1 : -1;
            if (balance < 0) return false;
        }
    }
    return balance == 0;
}
